# setup-pwa-gestao-projetos-v3.ps1
# Corrige icone do app e remove fallback visual da Vercel.
# Marcador: GESTAO_PROJETOS_PWA_V3

$ErrorActionPreference = "Stop"

Write-Host "Atualizando PWA e icones..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path ".\public\icons" | Out-Null

$icon192 = @"

"@

$icon512 = @"

"@

$appleIcon = @"

"@

$faviconPng = @"

"@

$faviconIco = @"

"@

[System.Convert]::FromBase64String($icon192) | Set-Content -Path ".\public\icons\icon-192.png" -Encoding Byte
[System.Convert]::FromBase64String($icon512) | Set-Content -Path ".\public\icons\icon-512.png" -Encoding Byte
[System.Convert]::FromBase64String($appleIcon) | Set-Content -Path ".\public\apple-touch-icon.png" -Encoding Byte
[System.Convert]::FromBase64String($faviconPng) | Set-Content -Path ".\public\favicon.png" -Encoding Byte
[System.Convert]::FromBase64String($faviconIco) | Set-Content -Path ".\public\favicon.ico" -Encoding Byte

@'
{
  "id": "/?app=gestao-projetos",
  "name": "Alexandre Dias | Gestão de Projetos",
  "short_name": "Gestão Projetos",
  "description": "Sistema premium para gestão de projetos de interiores, clientes, prazos e financeiro.",
  "start_url": "/?source=pwa",
  "scope": "/",
  "display": "standalone",
  "orientation": "portrait-primary",
  "background_color": "#f6efe4",
  "theme_color": "#2d1d17",
  "categories": ["productivity", "business"],
  "lang": "pt-BR",
  "icons": [
    {
      "src": "/icons/icon-192.png?v=3",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "any maskable"
    },
    {
      "src": "/icons/icon-512.png?v=3",
      "sizes": "512x512",
      "type": "image/png",
      "purpose": "any maskable"
    }
  ]
}
'@ | Set-Content -Path ".\public\manifest.webmanifest" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V3
const CACHE_NAME = "gestao-projetos-pwa-v3";
const APP_SHELL = [
  "/",
  "/manifest.webmanifest",
  "/favicon.ico",
  "/favicon.png",
  "/apple-touch-icon.png",
  "/icons/icon-192.png",
  "/icons/icon-512.png"
];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(APP_SHELL)).then(() => self.skipWaiting())
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)))
    ).then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") return;
  const url = new URL(event.request.url);
  if (url.origin !== self.location.origin) return;

  event.respondWith(
    fetch(event.request)
      .then((response) => {
        const copy = response.clone();
        caches.open(CACHE_NAME).then((cache) => cache.put(event.request, copy));
        return response;
      })
      .catch(() => caches.match(event.request).then((cached) => cached || caches.match("/")))
  );
});
'@ | Set-Content -Path ".\public\sw.js" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V3
if ("serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    navigator.serviceWorker
      .register("/sw.js")
      .catch((error) => console.warn("Service Worker não registrado:", error));
  });
}
'@ | Set-Content -Path ".\src\pwa-register.js" -Encoding UTF8

$indexPath = ".\index.html"
$index = Get-Content $indexPath -Raw

# Remove links/meta antigos que podem manter icone da Vercel/Vite/cache
$index = $index -replace '<link rel="icon" type="image/svg\+xml" href="/vite\.svg" />\s*', ''
$index = $index -replace '<link rel="icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="shortcut icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="apple-touch-icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="manifest"[^>]*>\s*', ''
$index = $index -replace '<meta name="theme-color"[^>]*>\s*', ''
$index = $index -replace '<meta name="mobile-web-app-capable"[^>]*>\s*', ''
$index = $index -replace '<meta name="apple-mobile-web-app-capable"[^>]*>\s*', ''
$index = $index -replace '<meta name="apple-mobile-web-app-title"[^>]*>\s*', ''
$index = $index -replace '<meta name="application-name"[^>]*>\s*', ''

$headTags = @'
    <!-- GESTAO_PROJETOS_PWA_V3 -->
    <link rel="manifest" href="/manifest.webmanifest?v=3" />
    <link rel="icon" href="/favicon.ico?v=3" sizes="any" />
    <link rel="icon" type="image/png" href="/favicon.png?v=3" />
    <link rel="apple-touch-icon" href="/apple-touch-icon.png?v=3" />
    <meta name="theme-color" content="#2d1d17" />
    <meta name="mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-title" content="Gestão Projetos" />
    <meta name="application-name" content="Gestão Projetos" />

'@

if ($index -match "GESTAO_PROJETOS_PWA_V[0-9]") {
  $index = $index -replace '<!-- GESTAO_PROJETOS_PWA_V[0-9] -->[\s\S]*?<meta name="application-name" content="[^"]*" />\s*', $headTags
} else {
  $index = $index -replace "<head>", "<head>`n$headTags"
}

if ($index -notmatch "/src/pwa-register.js") {
  $index = $index -replace "</body>", '    <script type="module" src="/src/pwa-register.js"></script>' + "`n  </body>"
}

Set-Content -Path $indexPath -Value $index -Encoding UTF8

Write-Host ""
Write-Host "PWA V3 atualizado com icone proprio." -ForegroundColor Green
Write-Host "Depois suba para Vercel e remova o atalho/app antigo do celular antes de instalar de novo." -ForegroundColor Yellow
